    _checkEventlessTransitions() {
        let changed = true;
        let iterations = 0;
        const maxIterations = 1000;

        while (changed && iterations < maxIterations) {
            changed = false;
            iterations++;

            // For each atomic state, find first matching eventless transition in lineage
            const enabledEventless = [];
            const addedTransitions = new Set();

            // Helper: get eventless transition for a state
            const getEventless = (stateId) => {
                return null;
            };

            // Find atomic states
            const atomicStates = [];
            for (const stateId of this.activeStates) {
                const children = this._getStateChildren(stateId);
                let hasActiveChild = false;
                for (const childId of children) {
                    if (this.activeStates.has(childId)) { hasActiveChild = true; break; }
                }
                if (!hasActiveChild) atomicStates.push(stateId);
            }

            // For each atomic state, traverse lineage and pick first matching
            atomicStates.sort((a, b) => this._getStateOrder(a) - this._getStateOrder(b));
            for (const atomicState of atomicStates) {
                let currentState = atomicState;
                while (currentState) {
                    const t = getEventless(currentState);
                    if (t) {
                        const key = t.source + ':' + t.priority;
                        if (!addedTransitions.has(key)) {
                            addedTransitions.add(key);
                            enabledEventless.push(t);
                        }
                        break;
                    }
                    currentState = this._getStateParent(currentState);
                }
            }

            // Filter conflicting and execute microstep
            if (enabledEventless.length > 0) {
                enabledEventless.sort((a, b) => a.priority - b.priority);
                const filtered = this._filterConflictingTransitions(enabledEventless);
                if (filtered.length > 0) {
                    changed = true;
                    // Exit in REVERSE document order
                    const sortedByReverse = [...filtered].sort((a, b) => b.priority - a.priority);
                    for (const t of sortedByReverse) t.exit();
                    // Content and enter in document order
                    filtered.sort((a, b) => a.priority - b.priority);
                    for (const t of filtered) t.content();
                    for (const t of filtered) t.enter();
                }
            }
        }
    }

