    /**
     * Get the event ID for an event name.
     * @param {string} eventName - The event name
     * @returns {number} The event ID or EVT_UNKNOWN (9999) if not found
     */
    getEventId(eventName) {
        return this.constructor.EVENT_MAP.get(eventName) ?? this.constructor.EVT_UNKNOWN;
    }

    /**
     * Get the event name for an event ID.
     * @param {number} eventId - The event ID
     * @returns {string|null} The event name or null if unknown
     */
    getEventName(eventId) {
        switch (eventId) {
            case 32: return 'C0WI';
            case 14: return 'C0DS';
            case 34: return 'C0WC';
            case 2: return 'init.done';
            case 6: return 'C0HO';
            case 9: return 'C0DI';
            case 8: return 'system.error';
            case 21: return 'C0FI';
            case 26: return 'C0PR';
            case 36: return 'C0HI';
            case 23: return 'C0PP';
            case 30: return 'load.done';
            case 13: return 'C0TR';
            case 39: return 'C0HF';
            case 10: return 'C0TP';
            case 37: return 'C0HC';
            case 17: return 'h96.error';
            case 24: return 'C0PG';
            case 1: return 'C0VI';
            case 12: return 'C0AS';
            case 29: return 'C0CR';
            case 35: return 'wash_ws.done';
            case 3: return 'C0KX';
            case 19: return 'C0ER';
            case 5: return 'C0CO';
            case 25: return 'isw.error';
            case 16: return 'C0EP';
            case 28: return 'C0CL';
            case 4: return 'C0KR';
            case 15: return 'C0EI';
            case 7: return 'C0ST';
            case 27: return 'C0II';
            case 38: return 'temp.reached';
            case 20: return 'C0ED';
            case 18: return 'C0EA';
            case 33: return 'C0WS';
            case 11: return 'pip.error';
            case 22: return 'C0FY';
            case 31: return 'unload.done';
            default: return null;
        }
    }

    /**
     * Send an event using its integer ID for optimized O(1) dispatch.
     * This bypasses string-to-ID lookup for maximum performance.
     * @param {number} eventId - The event ID (use EVT_* constants)
     * @param {*} [data=null] - Optional event data
     */
    sendById(eventId, data = null) {
        if (this._finished) return;
        const eventName = this.getEventName(eventId);
        if (eventName === null) {
            console.warn('Unknown event ID:', eventId);
            return;
        }
        this.send(eventName, data);
    }

    _matchEvent(eventName, pattern) {
        if (pattern === '*' || pattern === '.*') return true;
        if (pattern === eventName) return true;

        // Prefix matching: 'foo' matches 'foo.bar'
        if (eventName.startsWith(pattern + '.')) return true;

        // Handle space-separated patterns
        const patterns = pattern.split(/\s+/);
        for (const p of patterns) {
            if (p === '*' || p === '.*') return true;
            if (p === eventName) return true;
            if (p.endsWith('.*') && eventName.startsWith(p.slice(0, -2))) return true;
            if (eventName.startsWith(p + '.')) return true;
        }

        return false;
    }

    /**
     * Check if an event ID matches a pattern (internal use).
     * Uses integer comparison for known events, falls back to string for unknown.
     */
    _matchEventById(eventId, eventName, patternId, pattern) {
        // Fast path: wildcard '*' matches everything
        if (pattern === '*' || pattern === '.*') return true;

        // Fast path: exact match by ID (for known events)
        if (eventId !== this.constructor.EVT_UNKNOWN && eventId === patternId) return true;

        // For unknown events or prefix matching, fall back to string comparison
        return this._matchEvent(eventName, pattern);
    }


    static _ALL_EVENTS = new Set(['C0VI', 'init.done', 'C0KX', 'C0KR', 'C0CO', 'C0HO', 'C0ST', 'system.error', 'C0DI', 'C0TP', 'pip.error', 'C0AS', 'C0TR', 'C0DS', 'C0EI', 'C0EP', 'h96.error', 'C0EA', 'C0ER', 'C0ED', 'C0FI', 'C0FY', 'C0PP', 'C0PG', 'isw.error', 'C0PR', 'C0II', 'C0CL', 'C0CR', 'load.done', 'unload.done', 'C0WI', 'C0WS', 'C0WC', 'wash_ws.done', 'C0HI', 'C0HC', 'temp.reached', 'C0HF']);

